const https = require("https");
const http = require("http");
const fs = require("fs");
const path = require("path");
const url = require("url");

const PORT = process.env.PORT || 3000;
const OPENAI_KEY = process.env.OPENAI_API_KEY || "";
const TEMPLATE_B64 = "";

function buildPrompt(ev) {
  const name    = ev.name    || "EVENT";
  const venue   = ev.venue   || "";
  const day     = ev.day     || "";
  const date    = ev.date    || "";
  const dj      = ev.dj      || "";
  const genre   = ev.genre   || "";
  const time    = ev.time    || "";
  const entry   = ev.entry   || "";
  const contact = ev.contact || "";
  const extras  = ev.extras  || "";
  const details = [
    time    ? "Einlass: " + time + " Uhr" : "",
    entry   ? "Eintritt: " + entry : "",
    extras, contact
  ].filter(Boolean).join(" | ");

  return "Edit this nightclub event flyer. Keep ALL visual elements EXACTLY the same: the background, colors, atmosphere, decorative elements, people, lighting, textures, layout structure. ONLY change the text content to the following new event details:\n\n" +
    "Event name/title: \"" + name + "\"\n" +
    (genre ? "Genre/subtitle: \"" + genre + "\"\n" : "") +
    (day   ? "Day: \"" + day + "\"\n" : "") +
    (date  ? "Date: \"" + date + "\"\n" : "") +
    (dj    ? "DJ/Acts: \"" + dj + "\"\n" : "") +
    (venue ? "Venue: \"" + venue + "\"\n" : "") +
    (details ? "Details: \"" + details + "\"\n" : "") +
    "\nReplace every text element with the new information above. Keep the exact same font styles, sizes, colors, positions and visual design. The result must look 95% identical to the original — only the text content changes.";
}

const server = http.createServer((req, res) => {
  const p = url.parse(req.url).pathname;
  res.setHeader("Access-Control-Allow-Origin", "*");
  res.setHeader("Access-Control-Allow-Headers", "Content-Type");
  if (req.method === "OPTIONS") { res.writeHead(200); res.end(); return; }

  if (req.method === "GET" && p === "/") {
    fs.readFile(path.join(__dirname, "public", "index.html"), (err, data) => {
      if (err) { res.writeHead(404); res.end("Not found"); return; }
      res.setHeader("Content-Type", "text/html");
      res.writeHead(200); res.end(data);
    });
    return;
  }

  if (req.method === "POST" && p === "/api/generate") {
    if (!OPENAI_KEY) {
      res.writeHead(500);
      res.end(JSON.stringify({ error: "OPENAI_API_KEY not configured" }));
      return;
    }
    let body = "";
    req.on("data", c => body += c);
    req.on("end", () => {
      let ev;
      try { ev = JSON.parse(body); } catch(e) {
        res.writeHead(400); res.end(JSON.stringify({ error: "Invalid JSON" })); return;
      }

      const prompt = buildPrompt(ev);
      const imgBuffer = Buffer.from(TEMPLATE_B64, "base64");
      const boundary = "----NKBoundary" + Date.now().toString(36);
      const CRLF = "\r\n";

      const parts = [
        "--" + boundary + CRLF + "Content-Disposition: form-data; name=\"model\"" + CRLF + CRLF + "gpt-image-1",
        "--" + boundary + CRLF + "Content-Disposition: form-data; name=\"prompt\"" + CRLF + CRLF + prompt,
        "--" + boundary + CRLF + "Content-Disposition: form-data; name=\"n\"" + CRLF + CRLF + "1",
        "--" + boundary + CRLF + "Content-Disposition: form-data; name=\"size\"" + CRLF + CRLF + "1024x1536",
        "--" + boundary + CRLF + "Content-Disposition: form-data; name=\"quality\"" + CRLF + CRLF + "high"
      ].join(CRLF);

      const imgHeader = "--" + boundary + CRLF +
        "Content-Disposition: form-data; name=\"image[]\"  ; filename=\"template.png\"" + CRLF +
        "Content-Type: image/png" + CRLF + CRLF;
      const footer = CRLF + "--" + boundary + "--" + CRLF;

      const reqBody = Buffer.concat([
        Buffer.from(parts + CRLF, "utf8"),
        Buffer.from(imgHeader, "utf8"),
        imgBuffer,
        Buffer.from(footer, "utf8")
      ]);

      console.log("Calling OpenAI edit API, size:", reqBody.length);

      const apiReq = https.request({
        hostname: "api.openai.com",
        path: "/v1/images/edits",
        method: "POST",
        headers: {
          "Authorization": "Bearer " + OPENAI_KEY,
          "Content-Type": "multipart/form-data; boundary=" + boundary,
          "Content-Length": reqBody.length
        }
      }, apiRes => {
        let data = "";
        apiRes.on("data", c => data += c);
        apiRes.on("end", () => {
          console.log("OpenAI status:", apiRes.statusCode, data.substring(0, 200));
          try {
            const j = JSON.parse(data);
            if (apiRes.statusCode !== 200) {
              const msg = j.error?.message || data.substring(0, 200);
              res.writeHead(apiRes.statusCode);
              res.end(JSON.stringify({ error: msg }));
              return;
            }
            const img = j.data?.[0];
            let imgSrc = "";
            if (img?.b64_json) imgSrc = "data:image/png;base64," + img.b64_json;
            else if (img?.url) imgSrc = img.url;
            else { res.writeHead(500); res.end(JSON.stringify({ error: "No image in response" })); return; }
            res.setHeader("Content-Type", "application/json");
            res.writeHead(200);
            res.end(JSON.stringify({ url: imgSrc }));
          } catch(e) {
            res.writeHead(500);
            res.end(JSON.stringify({ error: "Parse error: " + data.substring(0, 200) }));
          }
        });
      });
      apiReq.on("error", e => {
        res.writeHead(500);
        res.end(JSON.stringify({ error: e.message }));
      });
      apiReq.write(reqBody);
      apiReq.end();
    });
    return;
  }

  res.writeHead(404); res.end("Not found");
});

server.timeout = 180000;
server.listen(PORT, () => console.log("NightKit (OpenAI) on port " + PORT));
